async function run(agent) {
  await agent.aiTap("进入 Menu");
  await agent.aiTap("点击 Settings");
  await agent.aiTap("点击 Visualization");
  await agent.aiTap("启用 Show OK Code Field");
  await agent.aiTap("保存 Visualization 设置");
  await agent.aiInput("OK Code / command field", { value: "ABAVN" });
  await agent.aiKeyboardPress("Enter");
  await agent.aiInput("Document date", { value: "<posting document date>" });
  await agent.aiInput("Asset value date", { value: "<asset value date>" });
  await agent.aiTap("从 listbox shell 中选择匹配资产/字段条目。");
  await agent.aiTap("切换到 Additional details 页签。");
  await agent.aiInput("Additional details required field", { value: "<SOP default>" });
  await agent.aiTap("切换到 Partial retirement 页签。");
  await agent.aiInput("Percentage rate", { value: "<percentage rate>" });
  await agent.aiTap("在 6A line items 的 amount / currency / cost center / order 表格中确认行项目。");
  await agent.aiTap("点击保存图标 sap_190 过账资产报废。");
  await agent.aiTap("在 Document lines Display messages 弹窗中点击 OK。");
  await agent.aiInput("Asset", { value: "<scrapped asset>" });
  const scrapValue = await agent.aiQuery("string, 在 Asset Explorer 读取 value、amount、ttype、transaction type name，确认报废交易行存在。");
  await agent.aiTap("从 SAP Easy Access 打开 Documents for Asset。");
  await agent.aiInput("Fiscal Year", { value: "<fiscal year>" });
  await agent.aiTap("在 Overview of Asset Accounting Documents 中选择报废 transaction 行。");
  await agent.aiTap("点击 Reverse。");
  await agent.aiInput("Reversal reason", { value: "01A" });
  await agent.aiTap("在 listbox shell 中选择 reversal reason 01A。");
  await agent.aiTap("打开 Reason for Reversal 搜索结果并选择匹配文本。");
  await agent.aiTap("点击 OK 确认 reversal reason。");
  await agent.aiTap("在 Overview 中确认冲销行项目后点击保存 sap_190。");
  await agent.aiTap("在 Document lines Display messages 中点击 OK。");
  const assetAfterReversal = await agent.aiQuery("string, 返回 Display Asset Master data / Asset values，读取报废后资产状态和值。");
  await agent.aiAssert("确认 Asset Explorer / Documents for Asset 中存在 scrapping transaction 和 reversal transaction。");
}
